# String iteration test (using to_runes)

meow catwalk_string_iter_each_char() {
  purr ch (to_runes("cat")) {
    nya(ch)
  }
  # Output:
  # c
  # a
  # t
}

meow catwalk_string_iter_with_index() {
  purr i, ch (to_runes("ab")) {
    nya(i)
    nya(ch)
  }
  # Output:
  # 0
  # a
  # 1
  # b
}

meow catwalk_string_iter_multibyte() {
  purr ch (to_runes("にゃん")) {
    nya(ch)
  }
  # Output:
  # に
  # ゃ
  # ん
}

meow catwalk_string_iter_multibyte_index() {
  purr i, ch (to_runes("にゃん")) {
    nya(i)
  }
  # Output:
  # 0
  # 1
  # 2
}

meow catwalk_string_iter_variable() {
  nyan word = "hi"
  purr ch (to_runes(word)) {
    nya(ch)
  }
  # Output:
  # h
  # i
}
